// src/components/ItemCard.jsx
import { Link } from 'react-router-dom';

const STATUS_COLORS = {
    open:     'success',
    matched:  'warning',
    resolved: 'secondary'
};

const TYPE_COLORS = {
    lost:  'danger',
    found: 'info'
};

const ItemCard = ({ item }) => {
    const imageUrl = item.image_path
        ? `http://localhost:5000${item.image_path}`
        : null;

    return (
        <div className="card h-100 shadow-sm">
            {imageUrl ? (
                <img
                    src={imageUrl}
                    className="card-img-top"
                    alt={item.title}
                    style={{ height: '180px', objectFit: 'cover' }}
                    onError={e => { e.target.style.display = 'none'; }}
                />
            ) : (
                <div className="bg-light d-flex align-items-center justify-content-center"
                     style={{ height: '180px', fontSize: '3rem' }}>
                    {item.type === 'lost' ? '🔍' : '📦'}
                </div>
            )}
            <div className="card-body">
                <div className="d-flex justify-content-between align-items-start mb-2">
                    <span className={`badge bg-${TYPE_COLORS[item.type]} text-uppercase`}>
                        {item.type}
                    </span>
                    <div>
                        <span className={`badge bg-${STATUS_COLORS[item.status]}`}>
                            {item.status}
                        </span>
                        {item.physically_verified && (
                            <span className="badge bg-success ms-1">✔ Verified by Police</span>
                        )}
                    </div>
                </div>
                <h6 className="card-title fw-bold">{item.title}</h6>
                <p className="card-text text-muted small">
                    {item.description.length > 80
                        ? item.description.slice(0, 80) + '...'
                        : item.description}
                </p>
            </div>
            <div className="card-footer d-flex justify-content-between align-items-center">
                <small className="text-muted">
                    By {item.reporter_name || 'Unknown'}<br />
                    {new Date(item.created_at).toLocaleDateString()}
                </small>
                <Link to={`/items/${item.id}`} className="btn btn-sm btn-outline-primary">
                    View
                </Link>
            </div>
        </div>
    );
};

export default ItemCard;
